starterCode.css:
body {
  font-family: system-ui, sans-serif;
  margin: 0;
  padding: 24px;
  background: white;
  color: #17201e;
  transition: background 0.2s, color 0.2s;
}

body.dark {
  background: #17201e;
  color: #f4f7f5;
}

button {
  padding: 8px 14px;
  border-radius: 8px;
  border: 1px solid currentColor;
  background: transparent;
  color: inherit;
  cursor: pointer;
}
